// Grab all items output by CloudConvert
const items = $input.all();

// Create a single item to hold everything, keeping the original webhook JSON
const mergedItem = {
  json: items[0].json,
  binary: {}
};

// Loop through the items and attach each image as a new property
items.forEach((item, index) => {
  if (item.binary && item.binary.data) {
    mergedItem.binary[`page_${index + 1}`] = item.binary.data;
  }
});

// Return exactly one item containing all pages
return [mergedItem];

// Parse the AI response and extract validation result
const aiResponse = $input.first().json.output || $input.first().json.text || '';

const webhookData = $('Start').first().json.body_firstItem;

let validationResult;
try {
  // Try to find JSON in the response
  const jsonMatch = aiResponse.match(/```json\s*([\s\S]*?)```/) || aiResponse.match(/(\{[\s\S]*\})/);

  if (jsonMatch) {
    const jsonStr = jsonMatch[1] || jsonMatch[0];
    validationResult = JSON.parse(jsonStr);
  } else {
    // If no JSON found, try parsing the whole response
    validationResult = JSON.parse(aiResponse);
  }
} catch (e) {
  // Fallback if parsing fails
  validationResult = {
    status: "ERROR",
    outcome: "Parsing Error",
    total_score: 0,
    safety_passed: false,
    category_scores: {},
    missing_evidence: ["Unable to parse AI response"],
    summary: "Validation could not be completed due to parsing error"
  };
}

// Add metadata to the result
return {
  json: {
    validation: validationResult,
    metadata: {
      order_id: webhookData.order_id,
      customer_name: webhookData.customer_name,
      submission_id: webhookData.submission_id,
      row_id: webhookData.row_id,
      pdf_filename: webhookData.installer_form_pdf?.filename,
      validated_at: new Date().toISOString()
    },
    // IMPORTANT: Checking for APROBADO instead of PASS
    passed: validationResult.status === 'APROBADO',
    raw_ai_response: aiResponse
  }
};

